import { writeOutput } from "./codegen";

const DOCS_URL = "https://msg9.io/SKILL.md";
const PLACEHOLDER_VALUE = "msg9_sk_CoffeeSafeLocalCoffeeSafeLocalCoffeeSafe";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from msg9 API docs.",
    `// Source: ${DOCS_URL}`,
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:msg9",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../firewall-types";',
    "",
    "export const msg9Firewall = {",
    '  name: "msg9",',
    '  description: "msg9 API",',
    "  placeholders: {",
    `    MSG9_TOKEN: "${PLACEHOLDER_VALUE}",`,
    "  },",
    "  apis: [",
    "    {",
    '      base: "https://www.msg9.io",',
    "      auth: {",
    "        headers: {",
    '          Authorization: "Bearer ${{ secrets.MSG9_TOKEN }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "  ],",
    "} as const satisfies FirewallConfig;",
    "",
  ];
  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating msg9 firewall config...");
  const ts = generateTypeScript();
  writeOutput("msg9", ts, import.meta.dirname);
}
